export const collocationsByTheme = (themeId: string) =>
  collocations.filter((c) => c.themeId === themeId);

export const collocationsBySubTheme = (subThemeId: string) =>
  collocations.filter((c) => c.subThemeId === subThemeId);

export const collocationById = (id: string) =>
  collocations.find((c) => c.id === id);
